class Solution:
    def numberOfSubstrings(self, s: str) -> int:
        counter = [0] * 3
        
        def is_valid_substring(counter):
            return all(n > 0 for n in counter)
        
        left, right, count = 0, 0, 0

        for right in range(len(s)):
            counter[ord(s[right]) - ord('a')] += 1

            while is_valid_substring(counter):
                # all substrings after a valid substring are valid so len(s) - current 
                # idx gives us the count of valid strings on and after the current idx
                count += len(s) - right

                counter[ord(s[left]) - ord('a')] -= 1
                left += 1

        return count

# Testcases:
sol = Solution()
print(sol.numberOfSubstrings("abcabc") == 10)
print(sol.numberOfSubstrings("aaacb") == 3)
print(sol.numberOfSubstrings("abc") == 1)
print(sol.numberOfSubstrings("") == 45830534)